oxy_webhelp_navlinks = {"azr_workloads-d27243e16355":{"topics":[{"title":"Introduction to Azure protection","href":"saas\/azr_key_features_protection.html","menu":{"hasChildren":false},"tocID":"tocId-d27243e16369","next":"tocId-d27243e16369"},{"title":"Get started with Azure workloads protection","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Azure workloads through a sequence of dependent         configuration steps. The implementation workflow provides a complete phase-by-phase         reference. The quickstart covers the minimum required steps to protect your first Azure         subscription.<\/p>","href":"saas\/azr_get_started_azure_protection.html","attributes":{"data-id":"azr_get_started_azure_protection"},"menu":{"hasChildren":false},"tocID":"azr_get_started_azure_protection-d27243e16448","next":"azr_get_started_azure_protection-d27243e16448"},{"title":"Plan your Azure protection","shortdesc":"<p class=\"shortdesc\">Before adding an Azure subscription to <span class=\"ph\">RSC<\/span>, establish <span class=\"ph\">RSC<\/span> user roles and review the permissions that <span class=\"ph\">RSC<\/span> requires         in your Azure environment.<\/p>","href":"saas\/azr_protection_planning.html","attributes":{"data-id":"azr_protection_planning"},"menu":{"hasChildren":false},"tocID":"azr_protection_planning-d27243e16489","next":"azr_protection_planning-d27243e16489"},{"title":"Set up Azure cloud accounts","shortdesc":"<p class=\"shortdesc\">You can add your Azure subscriptions to <span class=\"ph\">RSC<\/span> as cloud accounts to         enable workload discovery, protection, and recovery.<\/p>","href":"saas\/azr_cloud_acc_setup.html","attributes":{"data-id":"azr_cloud_acc_setup"},"menu":{"hasChildren":false},"tocID":"azr_cloud_acc_setup-d27243e16743","next":"azr_cloud_acc_setup-d27243e16743"},{"title":"Set up Exocompute on Azure","shortdesc":"<p class=\"shortdesc\">Exocompute on Azure uses an Azure Kubernetes Service (AKS) cluster in your         Azure subscription as compute infrastructure for data protection operations such as         file indexing, file recovery, and storage tiering.<\/p>","href":"saas\/azr_exocompute.html","attributes":{"data-id":"azr_exocompute"},"menu":{"hasChildren":false},"tocID":"azr_exocompute-d27243e17257","next":"azr_exocompute-d27243e17257"},{"title":"Set up Azure storage tiering","shortdesc":"<p class=\"shortdesc\">You can use Azure storage tiering to archive Azure virtual machine or managed disk         snapshots, which are older than a specified threshold, to Azure storage access tiers. By         archiving snapshots to these access tiers, you can optimize cost.<\/p>","href":"saas\/azr_storage_tiering_setup.html","attributes":{"data-id":"azr_storage_tiering_setup"},"menu":{"hasChildren":false},"tocID":"azr_storage_tiering_setup-d27243e17848","next":"azr_storage_tiering_setup-d27243e17848"},{"title":"Set up Azure workloads protection","shortdesc":"<p class=\"shortdesc\">You can set up SLA Domains to apply data protection policies, ensuring automatic and         hierarchical protection of Azure subscriptions, resource groups, and individual Azure         workloads, with granular control overriding higher-level assignments.<\/p>","href":"saas\/azr_workloads_protection_setup.html","attributes":{"data-id":"azr_workloads_protection_setup"},"menu":{"hasChildren":false},"tocID":"azr_workloads_protection_setup-d27243e18001","next":"azr_workloads_protection_setup-d27243e18001"},{"title":"Manage Azure virtual machines","shortdesc":"<p class=\"shortdesc\">After completing the protection setup for Azure virtual machines and managed disks,             <span class=\"ph\">RSC<\/span> takes automated snapshots of those virtual machines and disks based         on the configured policies in SLA Domains. You can also take on-demand snapshots, refresh         Azure subscriptions, and add Azure custom tags for better resource management.<\/p>","href":"saas\/azr_manage_vm_md.html","attributes":{"data-id":"azr_manage_vm_md"},"menu":{"hasChildren":false},"tocID":"azr_manage_vm_md-d27243e18276","next":"azr_manage_vm_md-d27243e18276"},{"title":"Manage Azure Blob Storage","shortdesc":"<p class=\"shortdesc\">By using the protection services offered by <span class=\"ph\">RSC<\/span>, you can protect and         recover your objects in Azure Blob Storage.<\/p>","href":"azure_blob\/azr_manage_blob_storage.html","attributes":{"data-id":"azr_manage_blob_storage"},"menu":{"hasChildren":false},"tocID":"azr_manage_blob_storage-d27243e18713","next":"azr_manage_blob_storage-d27243e18713"},{"title":"Manage Azure SQL Database","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> enhances Azure native backup capabilities for SQL Databases by         offering advanced, Rubrik-managed protection. This solution overcomes native limitations         with customizable SLA Domain policies, on-demand snapshots, and flexible cross-subscription         recovery, ensuring a consistent and automated approach to data security.<\/p>","href":"saas\/azr_sql_db_manage.html","attributes":{"data-id":"azr_sql_db_manage"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_manage-d27243e18853","next":"azr_sql_db_manage-d27243e18853"},{"title":"Manage Azure SQL Managed Instance","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> enhances Azure native backup capabilities for SQL Managed         Instances by offering advanced, Rubrik-managed protection. This solution overcomes native         limitations with customizable SLA Domain policies, on-demand snapshots, and flexible         cross-subscription recovery, ensuring a consistent and automated approach to data         security.<\/p>","href":"saas\/azr_sql_mi_manage.html","attributes":{"data-id":"azr_sql_mi_manage"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_manage-d27243e19155","next":"azr_sql_mi_manage-d27243e19155"},{"title":"Recover Azure workloads","shortdesc":"<p class=\"shortdesc\">After <span class=\"ph\">RSC<\/span> takes snapshots of your Azure workloads, you can recover         the required workloads.<\/p>","href":"saas\/azr_workload_recovery.html","attributes":{"data-id":"azr_workload_recovery"},"menu":{"hasChildren":false},"tocID":"azr_workload_recovery-d27243e19488","next":"azr_workload_recovery-d27243e19488"},{"title":"Quick links for Azure workloads","shortdesc":"<p class=\"shortdesc\">Immediate access to important tasks and information, enabling quick setup, daily         operations, and critical recovery.<\/p>","href":"saas\/azr_quick_links.html","attributes":{"data-id":"azr_quick_links"},"menu":{"hasChildren":false},"tocID":"azr_quick_links-d27243e19986","topics":[]}]}};